const body = $input.first().json;
const call = body.call || body;

const agentId = call.agent_id || '';
const callId = call.call_id || '';
const transcript = call.transcript || '';
const durationMs = call.duration_ms || 0;
const callStatus = call.call_status || '';

// Post-call analysis fields
const analysis = call.call_analysis || {};
const callSummary = analysis.call_summary || '';
const callSuccessful = analysis.call_successful || false;
const userSentiment = analysis.user_sentiment || '';

// Premium custom analysis fields
const bookingAttempted = analysis.booking_attempted || false;
const bookingSuccess = analysis.booking_success || false;
const appointmentDate = analysis.appointment_date || null;
const appointmentTimeWindow = analysis.appointment_time_window || null;
const jobTypeBooked = analysis.job_type_booked || null;
const rescheduleOrCancel = analysis.reschedule_or_cancel || 'neither';

return {
  agent_id: agentId,
  call_id: callId,
  transcript: transcript,
  duration_seconds: Math.round(durationMs / 1000),
  call_status: callStatus,
  call_summary: callSummary,
  call_successful: callSuccessful,
  caller_sentiment: userSentiment,
  booking_attempted: bookingAttempted,
  booking_success: bookingSuccess,
  appointment_date: appointmentDate,
  appointment_time_window: appointmentTimeWindow,
  job_type_booked: jobTypeBooked,
  reschedule_or_cancel: rescheduleOrCancel
};

const callData = $('Extract Call Data').first().json;
const supabaseRows = $input.first().json;

// Supabase returns array via httpRequest
const rows = Array.isArray(supabaseRows) ? supabaseRows : [supabaseRows];
if (!rows || rows.length === 0) {
  throw new Error('No client found for agent_id: ' + callData.agent_id);
}
const client = rows[0];

return {
  ...callData,
  company_name: client.company_name || '',
  client_email: client.client_email || '',
  lead_email: client.lead_email || '',
  lead_phone: client.lead_phone || '',
  lead_contact_method: client.lead_contact_method || 'Both',
  notification_email_2: client.notification_email_2 || '',
  notification_email_3: client.notification_email_3 || '',
  notification_sms_2: client.notification_sms_2 || '',
  notification_sms_3: client.notification_sms_3 || '',
  timezone: client.timezone || 'America/Chicago',
  calendar_platform: client.calendar_platform || '',
  crm_platform: client.crm_platform || ''
};

const gptResponse = $input.first().json;
const clientData = $('Parse Client Data').first().json;

let callData = {};
try {
  // Handle both native OpenAI node response and httpRequest response
  const choices = gptResponse.choices || gptResponse.message?.content;
  let text;
  if (gptResponse.choices) {
    text = gptResponse.choices[0]?.message?.content || '';
  } else {
    text = gptResponse.message?.content || gptResponse.text || JSON.stringify(gptResponse);
  }
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  callData = jsonMatch ? JSON.parse(jsonMatch[0]) : {};
} catch (e) {
  callData = { lead_score: 0, summary: 'Parse error', is_hot_lead: false, booking_attempted: false, booking_success: false };
}

const bookingAttempted = callData.booking_attempted || clientData.booking_attempted || false;
const bookingSuccess = callData.booking_success || clientData.booking_success || false;
const appointmentDate = callData.appointment_date || clientData.appointment_date || null;
const appointmentTimeWindow = callData.appointment_time_window || clientData.appointment_time_window || null;
const jobTypeBooked = callData.job_type_booked || clientData.job_type_booked || null;
const rescheduleOrCancel = callData.reschedule_or_cancel || clientData.reschedule_or_cancel || 'neither';
const leadScore = callData.lead_score || 0;
const isLead = bookingSuccess ? false : (leadScore >= 6);

return {
  ...clientData,
  ...callData,
  call_tier: 'premium',
  lead_score: leadScore,
  is_lead: isLead,
  booking_attempted: bookingAttempted,
  booking_success: bookingSuccess,
  appointment_date: appointmentDate,
  appointment_time_window: appointmentTimeWindow,
  job_type_booked: jobTypeBooked,
  reschedule_or_cancel: rescheduleOrCancel
};

